{"data":{"id":"275e7d4c-dfaa-4aff-944d-540f33309af9","name":"sup.....}}

api_key: eyJhbGciOiJIUzI1NiIsInR************
{"data":[{"id":"e41b59f9-f8da-468a-95a9-93de5b10df91","name":"realtime-dev"......}]}
```
### 3.2 在客户端应用上监听和发送广播

客户端可以通过 Realtime 库监听和发送广播消息。[参考文档](https://supabase.com/docs/guides/realtime/broadcast)

安装依赖：`npm i @supabase/realtime-js@2.11.15`

**监听广播示例代码**：将以下 JavaScript 代码集成到您的前端应用（如浏览器环境）或 Node.js 后端服务中运行

```js
import { RealtimeClient } from "@supabase/realtime-js";

const http_url = "https://supabase-realtime-160426-9-1307578329.sh.run.tcloudbase.com/socket"; // 替换为你的自定义域名或者使用默认域名进行测试
const api_key = "******"; // 替换为上文的api_key

const client = new RealtimeClient(http_url, { params: { apikey: api_key } });
const room = client.channel("room_01");
room
  .on(
    "broadcast",
    {
      event: "RoomBroadCast",
    },
    (payload) => {
      console.log("Recevie:", payload);
    }
  )
  .subscribe();
```

**发送广播示例代码**：将以下 JavaScript 代码集成到您的前端应用（如浏览器环境）或 Node.js 后端服务中运行

```js
import { RealtimeClient } from "@supabase/realtime-js";

const http_url = "https://supabase-realtime-160426-9-1307578329.sh.run.tcloudbase.com/socket"; // 替换为你的自定义域名或者使用默认域名进行测试
const api_key = "******"; // 替换为上文的api_key

const client = new RealtimeClient(http_url, { params: { apikey: api_key } });
const room = client.channel("room_01");

room.subscribe(async (status, err) => {
  if (status === "SUBSCRIBED") {
    await room.send({
      type: "broadcast",
      event: "RoomBroadCast",
      payload: {
        from_user: "client_1",
        to_user: "*",
        message: "client_1 join the room...",
      },
    });
  }
});
```
### 3.3 在客户端应用上监听存在状态

客户端可以通过 Realtime 库监听存在状态。[参考文档](https://supabase.com/docs/guides/realtime/presence)

**监听存在状态示例代码**：将以下 JavaScript 代码集成到您的前端应用（如浏览器环境）或 Node.js 后端服务中运行

```js
import { RealtimeClient } from "@supabase/realtime-js";

const http_url = "https://supabase-realtime-160426-9-1307578329.sh.run.tcloudbase.com/socket"; // 替换为你的自定义域名或者使用默认域名进行测试
const api_key = "******"; // 替换为上文的api_key

const client = new RealtimeClient(http_url, { params: { apikey: api_key } });
const room = client.channel("room_02");

room
  .on('presence', { event: 'sync' }, () => {
    const newState = room.presenceState()
    console.log('sync 同步', newState)
  })
  .on('presence', { event: 'join' }, ({ key, newPresences }) => {
    console.log('join 加入', key, newPresences)
  })
  .on('presence', { event: 'leave' }, ({ key, leftPresences }) => {
    console.log('leave 离开', key, leftPresences)
  })
  .subscribe()
```

**同步存在状态示例代码**：

```js
import { RealtimeClient } from "@supabase/realtime-js";

const http_url = "https://supabase-realtime-160426-9-1307578329.sh.run.tcloudbase.com/socket"; // 替换为你的自定义域名或者使用默认域名进行测试
const api_key = "******"; // 替换为上文的api_key

const client = new RealtimeClient(http_url, { params: { apikey: api_key } });
const room = client.channel("room_02");

const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

// 1. 等待订阅成功 为了方便演示，使用Promise, 实际使用参考官方文档示例
const subscribeStatus = await new Promise((resolve, reject) => {
  room.subscribe((status) => {
    if (status === 'SUBSCRIBED') resolve(status);
    else if (status === 'CHANNEL_ERROR') reject(new Error("Subscribe failed"));
  });
});

// 2. 同步 Presence 状态
const userStatus = { user: 'user-1', online_at: new Date().toISOString() };
const trackStatus = await room.track(userStatus);
console.log("Track status:", trackStatus);

// 3. 等待 5 秒
await delay(5000);
console.log("5秒等待完成");

// 4. 取消 Presence 同步
const untrackStatus = await room.untrack();
console.log("Untrack status:", untrackStatus);
```

