### 3.5 在微信小程序中使用

小程序开发者工具设置：
- 开启 -【详情】-【将JS编译成ES5】

`package.json`如下：

```json
{
  "dependencies": {
    "supabase-wechat-stable-v2": "^2.2.0",
    "tdesign-miniprogram": "^1.9.7"
  }
}
```

`index.wxml` 如下：

```xml
<!--index.wxml-->
<scroll-view class="scrollarea" scroll-y type="list">
  <view class="container">
    <view class="button-example">
      <t-button bind:tap="onButtonTap" data-type="broadcast" theme="primary" size="large" block>测试Broadcast</t-button>
      <view class="spacer"></view>
      <t-button bind:tap="onButtonTap" data-type="presence" theme="primary" size="large" block>测试Presence</t-button>
    </view>
  </view>
</scroll-view>
```

`index.js` 如下：

```js
// index.js
import {
  RealtimeClient
} from 'supabase-wechat-stable-v2/realtime-js/src'

const url = "ws://supabase-realtime-160426-9-1307578329.sh.run.tcloudbase.com/socket"; // 替换为你的自定义域名或者使用默认域名进行测试
const api_key = "******"; // 替换为上文的api_key

Page({
  data: {},
  onButtonTap: function (event) {
    const buttonType = event.currentTarget.dataset.type; // 获取按钮标识

    // 初始化公共客户端
    const client = new RealtimeClient(url, {
      params: { "apikey": api_key }
    });

    // 根据按钮类型执行不同逻辑
    if (buttonType === 'broadcast') {
      this.handleBroadcast(client);
    } else if (buttonType === 'presence') {
      this.handlePresence(client);
    }
  },

  // Broadcast处理逻辑
  handleBroadcast: function (client) {
    console.log("Broadcast按钮触发");
    const room = client.channel('room_01');
    room.subscribe(async (status, err) => {
      if (status === 'SUBSCRIBED') {
        await room.send({
          type: 'broadcast',
          event: 'RoomBroadCast',
          payload: {
            from_user: "wx_client_1",
            to_user: "*",
            message: 'wx_client_1 join the room...'
          },
        })
      }
    })
  },

  // Presence处理逻辑
  handlePresence: function (client) {
    console.log("Presence按钮触发");
    const room = client.channel('room_02');
    const userStatus = {
      user: 'wx-user-1',
      online_at: new Date().toISOString(),
    }
    room.subscribe(async (status) => {
      if (status == 'SUBSCRIBED') {
        const presenceTrackStatus = await room.track(userStatus)
        console.log(presenceTrackStatus)
      }
    })
  }
})
```
## 4. 其他注意事项

**数据持久性**：实时通讯示例默认不持久保存数据库数据，服务重启后 tenants 信息可能丢失。建议在服务启动时检查并重建 tenants。
**域名使用**：强烈建议在生产环境中使用自定义域名，云托管提供的默认域名仅适用于调试。
**运行方式**：建议使用“持续运行”的方式部署实时通讯服务，以避免服务重启后需要重新初始化的问题。

更多配置方式，请参考[Supabase Realtime GitHub 仓库](https://github.com/supabase/realtime)。

更多示例用法，请参考[Supabase Realtime 文档](https://supabase.com/docs/guides/realtime)

# Hono 云函数使用示例

该模板演示了如何在云函数环境中使用 Honojs 框架，包含多种功能接口。以下是各个接口的使用示例，包括云函数调用和 HTTP 请求调用方式。

**使用 HTTP 访问前，需要前往 云开发平台-云函数-函数配置 设定 HTTP 访问服务路径。**

## 1. 基础接口调用

### 获取文本响应

**云函数调用方式：**
```js
// 小程序中调用示例
wx.cloud.callFunction({
  name: 'hono-template',
  data: { path: '/' }, // 请求根路径
}).then((res) => {
  console.log('文本响应结果:', res.result.body); // 输出: Hello Hono!
})
```

**HTTP 请求方式：**
```js
// 假设云函数HTTP服务地址为 https://your-domain.com/hono-template
fetch('https://your-domain.com/hono-template/')
  .then(response => response.text())
  .then(data => {
    console.log('文本响应结果:', data); // 输出: Hello Hono!
  });
```

**curl 命令：**
```bash
curl https://your-domain.com/hono-template/
```

### 获取JSON数据

**云函数调用方式：**
```js
// 小程序中调用示例
wx.cloud.callFunction({
  name: 'hono-template',
  data: { path: '/json' },
}).then((res) => {
  console.log('JSON响应结果:', JSON.parse(res.result.body));
  // 输出: { data: { a: 123 }, code: 200 }
});
```

**HTTP 请求方式：**
```js
fetch('https://your-domain.com/hono-template/json')
  .then(response => response.json())
  .then(data => {
    console.log('JSON响应结果:', data);
    // 输出: { data: { a: 123 }, code: 200 }
  });
```

**curl 命令：**
```bash
curl https://your-domain.com/hono-template/json
```

## 2. 图片代理功能

**HTTP 请求方式：**
```js
// 在浏览器或其他环境中直接使用
const imageUrl = 'https://your-domain.com/hono-template/image?url=' + 
                 encodeURIComponent('https://example.com/sample-image.jpg');

// 直接在img标签中使用
document.getElementById('proxyImage').src = imageUrl;
```

## 3. 文件上传功能

**HTTP 请求方式：**
```js
// 在浏览器中使用FormData上传文件
const fileInput = document.getElementById('fileInput');
fileInput.addEventListener('change', async (e) => {
  const file = e.target.files[0];
  if (!file) return;

  const formData = new FormData();
  formData.append('file', file);

  try {
    const response = await fetch('https://your-domain.com/hono-template/upload', {
      method: 'POST',
      body: formData
    });
    const result = await response.json();
    console.log('文件上传信息:', result);
  } catch (error) {
    console.error('上传失败:', error);
  }
});
```

**curl 命令上传文件：**
```bash
curl -X POST https://your-domain.com/hono-template/upload \
  -F "file=@/path/to/local/file.jpg"
```

## 4. 定时触发器使用

定时触发器主要由云函数平台根据配置的时间自动触发，但也可以手动模拟触发。

### 配置定时触发器

**手动模拟触发（HTTP方式）：**
```js
fetch('https://your-domain.com/hono-template/CLOUDBASE_TIMER_TRIGGER/daily-task')
  .then(response => response.json())
  .then(data => {
    console.log('定时器测试结果:', data);
  });
```

**curl 命令模拟触发：**
```bash
curl https://your-domain.com/hono-template/CLOUDBASE_TIMER_TRIGGER/daily-task
```

当触发器被触发时，云函数会返回如下结果：
```json
{
  "message": "定时器 daily-task 成功执行",
  "timestamp": "2023-08-15T08:00:00.123Z",
  "originalEvent": {...触发器事件对象...}
}
```

---

通过上述方式，您可以根据自己的应用场景选择合适的调用方式，以灵活地使用 Hono 框架构建云函数应用。

