  name: 'custom-auth',
  data: {
    action: 'login',
    data: {
      username: 'test@example.com',
      password: 'password123'
    }
  }
}).then(res => {
  console.log('Login result:', res)
})

// Response Example
{
  "accessToken": "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...",
  "refreshToken": "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...",
