    }
  }
}).then(res => {
  console.log('Transfer: ', res)
})

// response
{
  "success": true,
  "recordId": "xxx"
}

// Batch Transfer
wx.cloud.callFunction({
  name: 'transaction-management',
  data: {
    action: 'batchTransfer',
    data: {
      fromAccountId: 'account1',
      transfers: [
        { toAccountId: 'account2', amount: 50 },
        { toAccountId: 'account3', amount: 50 }
      ]
